var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이거 미안하게 됐군.","JPN":"君には悪いことをしてしまった。","ENG":"I must apologize for this.","TWN":"我必須向你道歉，克萊爾小姐。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 자네의 관심을 사려면 이 방법이 가장 확실하다고 생각했거든.","JPN":"だが、君の興味を引くにはこの手が一番手っ取り早いと思ったのだよ。","ENG":"But it was the surest way of getting your attention.","TWN":"不過，我認為這是最能引起你興趣的方法。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 우리에게 주어진 시간이 그리 많지 않아서 말이야.","JPN":"なにより、私たちにはあまり時間がないものでね。","ENG":"You see, we don't have much time.","TWN":"最重要的是，我們的時間不多了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"방식이 다소 무례하더라도 부디 이해해 주길 바라네.","JPN":"無礼なやり方をしてしまったが、どうか理解してほしい。","ENG":"I hope you understand, even if my methods were rash.","TWN":"方式有些無禮，還請見諒。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哈啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"허례허식은 집어치우세요.","JPN":"正直に答えてください。","ENG":"Enough with the pretentiousness.","TWN":"別說客套話了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어디까지 알고 있죠? 그분께서 보낸 사람인가요?","JPN":"どこまで知っているのですか？　あの人の使いで来たのですか？","ENG":"How much do you know? Did that person send you to me?","TWN":"你到底知道多少？是那位派你來的嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그럴 리는 없겠네요. 만약 그랬으면 편지를 빼앗긴 시점에서 전 살해당했을 테니까.","JPN":"いや、違いますね。もしそうだったら、手紙を奪われた時点で私は殺されていたはず。","ENG":"No, that can't be right. Because that would mean that I'd already be dead by the time it was stolen from me.","TWN":"不，不太可能。如果真是那樣的話，我在信被搶走的那一刻就已經被殺了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 대체 당신은 정체가 뭔가요? 저한테 뭘 원하는 거죠?","JPN":"ではあなたの望みは何ですか？　あなたは誰なんですか？","ENG":"Then, who are you? What do you want from me?","TWN":"那你到底是誰？你想從我這裡得到什麼？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"전에 봤을 때의 우아한 태도는 온데간데없군.","JPN":"前回の優雅な態度が嘘のようだな。","ENG":"Your graceful attitude I saw before seems to have gone away.","TWN":"之前看到的優雅態度已經不復在了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 연기를 하지 않는 자네의 원래 성격인가?","JPN":"それが、役を演じていない素の君なのかね？","ENG":"Is this your true personality?","TWN":"這就是你不演戲時的本性嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요, 모두가 타인을 대할 때 적당한 가면을 고르지 않나요?","JPN":"さあ、誰しも他人と向き合う時は、相応の仮面を被るものでしょう。","ENG":"Well, doesn't everyone choose an appropriate mask when dealing with other people?","TWN":"呵，大家在面對別人時不都會選擇戴上合適的面具嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"비슷한 거예요. 상대방이 원하는 배역을 연기해주면, 바라는 걸 쉽게 얻을 수 있으니까.","JPN":"それと同じです。相手の望む役を演じてあげれば、こちらも目的を果たすのは容易い。","ENG":"Let's say it's something similar. Because it's easier to get what I want if I play the role others expect.","TWN":"只要演好對方期望的角色，就能輕鬆得到自己想要的東西。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"타인에게 완벽히 솔직한 사람은 없어요. 다들 적당히 속고, 속이며 살죠.","JPN":"他人に本当の自分をさらけ出す人などいません。皆適当にだまし、だまされて生きているんです。","ENG":"Nobody is completely honest with others. They all cheat and deceive one another.","TWN":"沒有人會對他人完全坦誠，大家都在恰如其分的欺騙和被欺騙中生活。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신에겐, 그저 연기할 가치조차 못 느낄 뿐.","JPN":"あなたには、演技する価値すら感じていないだけ。","ENG":"It's just that I don't see any reason to act in front of you.","TWN":"只是對現在的你來說，演戲並沒有什麼意義。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 곱상한 외모와는 달리 꽤나 독설가로군.","JPN":"ふふ、綺麗な顔にそぐわず、かなりの毒舌だな。","ENG":"Haha. You have quite the sharp tongue unlike that pretty face you have.","TWN":"呵呵，好一個長相貌美，口齒伶俐的女生。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 식으로 왕국의 왕세자를 협박하여, 매달 큰 돈을 갈취해 온 건가?","JPN":"そんな風に皇太子を脅し、毎月大金をゆすり取っていたのか。","ENG":"Have you been threatening the prince and extorting money from him every month?","TWN":"你也是這樣威脅一位王國的王儲，每個月勒索大筆錢財的嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하! 협박이라고요?","JPN":"は！　脅すですって？","ENG":"Ha! Threaten him?","TWN":"哈！威脅他？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"안타깝게도 그 분에게 목숨을 위협받고 있는 건 오히려 저랍니다.","JPN":"残念ながら、あの方に命を脅かされているのは私のほうです。","ENG":"Unfortunately, I'm the one being threatened by him.","TWN":"可惜的是，受到生命威脅的反而是我。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"목숨을 위협받는다라?","JPN":"命を脅かされている？","ENG":"You're being threatened?","TWN":"生命威脅？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"추정컨대, 그분께서는 평민 출신 오페라 배우와 찍은 사진이 정치적으로 발목을 잡게 될 거라고 생각하신 모양이에요.","JPN":"あの方は平民出身のオペラ女優と撮った写真が、自分の政治的な足手まといになると思っているらしくて。","ENG":"I assume that he never imagined that he would be in political danger from taking a photo with a commoner opera actress.","TWN":"他大概是認為，與平民出身的歌劇演員拍照會成為政治上的絆腳石。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제 열렬한 팬을 자처하면서 멋대로 <color=#ffd34c>사진</color>을 찍자고 할 땐 언제고.","JPN":"自分から熱烈なファンを名乗り、私と<color=#ffd34c>写真</color>を撮ろうと言ってきたくせに。","ENG":"He's the one who said he was my biggest fan and insisted that I take a <color=#ffd34c>photo</color> with him.","TWN":"原本還自稱是我忠實粉絲的時候，硬要跟我<color=#ffd34c>合照</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이제는 그 사진 때문에 자기 혼삿길이 막힐지도 모른다고 벌벌 떨더군요.","JPN":"ここにきて、あの写真のせいで自分の縁談が上手くいかないかもしれないと怯えているんです。","ENG":"He is now terrified that his chances of getting married will be ruined as a result.","TWN":"現在因為那張照片，擔心自己的婚事可能會泡湯，嚇得發抖。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 대단한 일이죠.","JPN":"まったく大層なお方ですよね。","ENG":"The nerve he has.","TWN":"真是了不起啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그분은 제가 유명해질수록 스캔들이 알려질 가능성이 커질 거라고 했어요.","JPN":"あの方は私が有名になればなるほど、スキャンダルが漏れる可能性が高まると言っていました。","ENG":"He said that the more famous I get, the higher the risk of the scandal getting out.","TWN":"他說我越出名，醜聞被揭露的可能性就越大。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 저에게 배우를 그만두든지, 사진을 내놓든지……. 둘 중 하나를 선택하라고 하더군요.","JPN":"だから私に俳優を辞めるか、写真を差し出すかどっちかを選べと言い出したんです。","ENG":"So, he told me to choose.... either quitting acting, or give him the photo.","TWN":"所以讓我選擇，要麼退出演員圈，要麼交出照片……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"둘 다 거절했더니……. 다음에는 살인청부업자를 보내서 제 목을 노렸죠.","JPN":"どちらも断ったら、今度は殺し屋を雇って私の命を狙った。","ENG":"I declined both... and then he hired a hitman to kill me.","TWN":"我兩邊都拒絕了……但接下來他就派出了殺手。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"목숨을 지킬 수 있는 유일한 수단은 언론에 사진을 공개하겠다고 협박하는 것뿐이었어요.","JPN":"自分の命を守るために私が取れる手段は、マスコミに写真を公開してやると脅迫することしかなかったんです。","ENG":"The only reason I'm able to stay alive is because I threatened him that I'll release the photo to the media.","TWN":"唯一能保命的辦法，就是威脅他要把照片公開給媒體。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 그 과정에서 푼돈을 뜯어내긴 했지만.","JPN":"まあ、その流れでちょっとお金を要求したのは事実ですが。","ENG":"Of course, I did ask for chump change as well in the process.","TWN":"當然，在這個過程中也賺了一些小錢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"으음, 하지만 이상하군.","JPN":"うむ、しかしおかしいな。","ENG":"Mm... but something doesn't sit right.","TWN":"嗯，不過我有些奇怪。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼 어째서 사진을 넘기지 않은 거지? 목숨이 노려지는 것보단 나을 텐데?","JPN":"なぜ写真を渡さなかったのかね？　命を狙われるよりはマシだろう。","ENG":"Why haven't you handed the photo over to him? Isn't it better than having someone after your life?","TWN":"為什麼不交出照片呢？總比被盯上性命要好吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무것도 모르는 건가요? 아니면 모르는 척하는 건가요?","JPN":"本当にわからないんですか？　それとも分からないふりをしてるんですか？","ENG":"Do you know anything? Or are you playing dumb with me?","TWN":"你是真的不知道，還是在裝傻？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그분은 이미 제 입을 막기 위해, 몇 번이나 살인청부업자를 보냈다고요.","JPN":"あの方は口止めのために、もう何度も私に殺し屋を送り込んでいるんですよ。","ENG":"I said that he's already sent out a hitman several times to keep my mouth shut.","TWN":"為了堵住我的嘴，他已經派了好幾個殺手。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사진을 넘겨봤자, 결국 순서만 달라질 뿐이겠죠.","JPN":"写真を渡したところで、順番が変わるだけです。","ENG":"Nothing will change even if I hand it over to him.","TWN":"即使把照片交出去，最終也是這樣的結果吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어차피 그분에게 있어, 제 목숨 같은 건 벌레만도 못할 테니까요.","JPN":"どうせあの方にとって私の命なんか虫けら同然ですから。","ENG":"Because to him, my life is worth less than a fly.","TWN":"反正對他來說，我的命連螞蟻都不如。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고…… 이젠 제 목숨줄이 당신 손에 들려 있네요.","JPN":"そして……私の命はもう、あなたの手にかかっていますね。","ENG":"Also... now, my life is in your hands.","TWN":"現在……我的命運掌握在你的手中。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"좋아요. 사진을 어쩌실 생각인지 모르겠지만, 궁금하네요.","JPN":"いいでしょう。写真をどうするつもりかはわかりませんが……一つ、気になることがあります。","ENG":"All right. I don't know what you're going to do with that photo, but I'm curious.","TWN":"好吧。我不知道你打算怎麼處理那張照片，但我很好奇。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어떻게 제가 팬레터 속에 사진을 숨겼다는 걸 알아낸 거죠?","JPN":"いったいどうやって、私がファンレターの中に写真を隠していたとわかったんですか？","ENG":"How did you know that I was hiding the photo in that fan letter?","TWN":"你到底是怎麼發現我在粉絲信裡藏了照片的？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건, 제 나름대로 공들여 구상해낸 <color=#ffd34c>각본</color>이었어요.","JPN":"あれは私なりに念入りに考えた<color=#ffd34c>脚本</color>だったのに。","ENG":"That is a <color=#ffd34c>script</color> that took me some effort to come up with.","TWN":"那是我精心構思的<color=#ffd34c>劇本</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"지금까지 그 누구에게도 들킨 적 없었고요.","JPN":"今まで誰にもバレたことはありません。","ENG":"No one has ever caught on until now.","TWN":"至今為止從未被任何人發現過。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 확실히…….","JPN":"ふふ、確かに……","ENG":"Haha, most certainly...","TWN":"呵呵，確實……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"소중한 물건일수록 자신으로부터 가장 멀리 떨어트려 두는 것은 현명한 선택이야.","JPN":"大事なものほど、身近に置かないようにするというのは懸命な判断だ。","ENG":"It's wise of you to keep precious items as far away from you as possible.","TWN":"越是珍貴的東西，越要放得離自己最遠，這是明智的選擇。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 왕립 우정국 서비스를 개인 금고처럼 사용하면 곤란해.","JPN":"しかし王立郵政局のサービスを、プライベート金庫のように使われては困るよ。","ENG":"But using the Royal Postal Service as your personal safe is not good.","TWN":"但是把皇家郵政服務當作私人保險箱使用是不行的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네.","JPN":"簡単な話だ。","ENG":"It's elementary, my dear.","TWN":"這是很簡單的推理，親愛的女士。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 그 사진을 가지고 있으면, 언젠가 왕세자께 빼앗길 것이라고 확신했어.","JPN":"君はこの写真を持っていれば、いつか皇太子に奪われるだろうと確信した。","ENG":"You are certain that if you have the photo with you, the prince will one day take it from you.","TWN":"你知道拿著那張照片的話，總有一天會被王儲搶走。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다고 목숨이 달린 사진을 누군가에게 맡겨 놓을 수도 없는 노릇이었지.","JPN":"だからと言って、命がかかっている写真を他人に任せるわけにもいかない。","ENG":"Then again, entrusting someone else with a photo that your life depends on is also not a wise plan.","TWN":"但把關乎自身性命的照片交給別人保管也並非明智之選。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 좀처럼 타인을 믿지 않는 성격이야.","JPN":"君はなかなか他人を信用しないタイプだ。","ENG":"It seems that you're the type of person who rarely trusts others.","TWN":"你是那種很難相信別人的性格。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"누구에게도 알리지 않고, 혼자 사진을 절대 들키지 않는 곳에 감추어야만 했어.","JPN":"誰にも知られず、一人で写真を決してバレない場所に隠すしかなかったんだ。","ENG":"So, you had to hide it and never tell a soul.","TWN":"所以必須不讓任何人知道，獨自把照片藏在絕對不會被發現的地方。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 팬레터를 이용하기로 한 거야.","JPN":"だからファンレターを利用したのさ。","ENG":"That's why you disguised it as a fan letter.","TWN":"於是，你想到了利用粉絲信。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"매일 쏟아지던 팬레터 속에 자기 자신에게 보낸 팬레터를 몰래 숨겨두는 거지.","JPN":"自分自身にファンレターを出し、毎日山ほど届けられる手紙の中に隠したんだろう。","ENG":"You were able to hide it in the pile of other fan letters you get each day.","TWN":"在每天堆積如山的粉絲信中，偷偷夾帶一封寫給自己的信。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"나무를 숨길 때는 숲에 숨기라는 말도 있지 않나?","JPN":"木を隠すなら森の中、と言うじゃないか。","ENG":"Didn't someone say to hide a tree, one must do it in a forest?","TWN":"不是有句話說，想把一棵樹藏起來，最好的辦法就是藏在森林裡嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이 방법에는 큰 문제가 있어.","JPN":"しかしこの方法には大きな問題点がある。","ENG":"However, that method has one massive flaw.","TWN":"但是這個方法有很大的問題。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무런 안전장치 없이 그냥 편지를 보냈다간 배송이 제대로 안 될 수도 있거든.","JPN":"なんの安全装置もなく手紙を送っては、配送事故が起こるかもしれない。","ENG":"There are no safety measures that ensure the letter will be delivered.","TWN":"如果沒有任何安全措施，寄出的信可能無法正常送達。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"오히려 목숨이 달려있는 사진을 분실할 가능성도 적지 않았지.","JPN":"命がかかっている写真を紛失する可能性だってある。","ENG":"It may even raise the risk of losing the photo your life depends on.","TWN":"那麼，反而是丟失性命攸關的照片的可能性不小。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 자네는 계책을 떠올렸어. 바로 왕실 우표를 사용하는 거야.","JPN":"だから君は妙策を思いついた。王室の切手を使うのさ。","ENG":"So, you came up with a scheme to use the royal stamp.","TWN":"所以你又想出了一個計策，就是使用王室郵票。"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 우표가 붙어있는 편지는 특별히 관리되며, 매주 정확한 시간에 수신자에게 직접 전달하도록 되어 있거든.","JPN":"王室の切手が貼られている手紙は特別に管理され、毎週正確な時間に、受取人に直接届けられるようになっている。","ENG":"Letters with the royal stamp are given special treatment, being delivered directly to the recipient on the exact time each week.","TWN":"貼有王室郵票的信件會被特別管理，每週準時、直接地送到收件人手中。"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 방법이라면, 편지가 배송되는 일주일간 사진이 자네의 손을 떠나 있으면서도.","JPN":"この方法なら、手紙が配送されるまでの一週間、写真を君の手元から離すことができる。","ENG":"With this, even if the photo is not within your possession for a week,","TWN":"用這種方法，在信件寄出的整整一周配送時間內，照片也會離開你的手邊。"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"동시에 그 일주일간 어떤 금고보다도 안전하게 사진을 보관할 수 있어.","JPN":"同時に、どこの金庫よりも安全な場所に写真を保管できるわけだ。","ENG":"you are able to keep it safely hidden and stored during that week.","TWN":"同時，那一周內可以比任何保險箱更安全地保存照片。"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 우표 가격이 터무니없이 비싸긴 하지만…….","JPN":"もちろん、かなり値が張るが……","ENG":"Of course, the cost of the stamp is ridiculously expensive, but...","TWN":"當然，郵票的價格確實貴得離譜……"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실의 명예를 걸고 그 신뢰성을 보장한다는 뜻이니까, 믿을 수 있지.","JPN":"王室の名誉にかけて保証されているサービスだ。十分信用できる。","ENG":"you can trust it as the royal family's honor guarantees its safety.","TWN":"不過以王室的名譽作為擔保，所以可以讓你放心。"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MANSION","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 일부러 왕실 우표를 썼던 이유는 한 가지 더 있어.","JPN":"君がわざと王室の切手を使った理由はもう一つある。","ENG":"There is also another reason for your using the royal stamp.","TWN":"你特意使用王室郵票還有另一個原因。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 우표의 주요 고객은 왕족이나 귀족들이야.","JPN":"王室の切手を使う客層は、ほとんどが王族か貴族だ。","ENG":"The main demographic of the royal stamps are royals and nobles.","TWN":"王室郵票的主要客戶是皇室或者貴族。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그런 높으신 분들은 종종 발신인을 숨긴 채, 편지를 보내기도 하지.","JPN":"そういったお偉い方々は、時々差出人を伏せて手紙を送ることがある。","ENG":"And many of them frequently send letters without writing the sender.","TWN":"而那些身分高貴的人經常會隱藏寄件者寄信。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 왕실 우표가 붙은 팬레터를 이용해서 은연 중에 고위층의 <color=#ffd34c>위험한 팬</color>이 있다는 걸 드러낼 수 있었어.","JPN":"君は王室の切手が貼られたファンレターを利用して、上流階級出身の<color=#ffd34c>危険なファン</color>がいるということを匂わせることができた。","ENG":"This way, you were able to use the fan letter with the royal stamp to hint at others that there was a high-ranking <color=#ffd34c>dangerous fan</color>.","TWN":"你利用貼有王室郵票的粉絲信，暗示了上流社會中有<color=#ffd34c>危險的粉絲</color>。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……맞아요.","JPN":"……そのとおりです。","ENG":"...You're right about it all.","TWN":"……沒錯。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제 신변에 문제가 생기면, 메리는 제가 보냈던 그 팬레터를 읽게 될 거고.","JPN":"私の身に何か起きれば、メリーはあのファンレターを開けるでしょう。","ENG":"If anything happened to me, Mary will read the fan letter I sent to myself,","TWN":"如果我出了什麼事，瑪麗就會讀到我寄給自己的那封粉絲信。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 안에 든 사진을 신문사에 보내겠죠.","JPN":"そしてその中の写真を新聞社に送るはずです。","ENG":"and she will give the photo inside to a newspaper company.","TWN":"然後她便會把裡面的照片寄給報社。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메리가 그런 식으로 행동하게끔, 줄곧 연기해왔으니까요.","JPN":"メリーが必ずそうするように、今まで演じながら誘導してきたので。","ENG":"I've been acting all this time to condition Mary to do so.","TWN":"為了讓瑪麗能夠那樣行動，我也一直在演戲。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 마치 잘 짜인 각본처럼 말이지.","JPN":"ふふ、よく練られた脚本みたいにね。","ENG":"Haha, it's as if I'm reading a well-written script.","TWN":"哈哈，就像精心編排的劇本一樣。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"결과적으로 나는 자네가 팬레터를 부친 직후를 노릴 수밖에 없었다네.","JPN":"結果的に、私は君がファンレターを出した直後を狙うしかなった。","ENG":"In the end, I had no choice but to target the exact moment you sent the fan letter.","TWN":"這樣的話，我就只能選擇在你寄出粉絲信之後行動了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"일단 팬레터가 집배 되면, 아무리 나라도 그걸 빼돌리는 건 귀찮아지거든.","JPN":"ファンレターが集配されてしまうと、いくら私でもそれを横取りするのは手間がかかるのでね。","ENG":"Once it goes into sorting, it'll be too bothersome even for me to try and steal it.","TWN":"一旦粉絲信送到了郵局，想再把它拿回來就很麻煩了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"귀찮다고요?","JPN":"手間ですって？","ENG":"Bothersome?","TWN":"麻煩？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그보다 그 말은 절 미행했다는 뜻이잖아요?","JPN":"いや、それより私を尾行していたんですか？","ENG":"No, wait. That means that you've been following me.","TWN":"不，不對，那也就是說你跟蹤我了？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 팬레터를 부쳤던 그날은 분명…… ","JPN":"でもファンレターを投函したあの夜は確か…… ","ENG":"But the night I put the letter in the postbox...","TWN":"但是寄出信的那天，明明是……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐?","JPN":"待って。","ENG":"What?","TWN":"等等？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 설마 그 퇴역 군인이……?","JPN":"じゃあまさか、あの退役軍人は……？","ENG":"Then that ex-soldier is...?","TWN":"難道說那個退役軍人……？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"맞아, 그는 내가 섭외해둔 인물이었다네.","JPN":"そうだよ、彼は私が手配した人物だ。","ENG":"Yes. He is someone that I recruited.","TWN":"沒錯，他也是我事先安排好的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 주의를 돌리는 동시에 자네가 날 의심하지 않도록 만들 생각이었거든.","JPN":"君の注意を彼にそらすと同時に、私が疑われないようにするためにね。","ENG":"It was to distract your attention while also make you not suspect me.","TWN":"為的是在轉移你注意力的同時，讓你不懷疑我。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"완전히 당했네요. 그 상황 자체가 당신의 연출이었다니…….","JPN":"完全にやられましたね。あの状況はあなたが演出したものだったとは……","ENG":"I was completely fooled. I never imagined the entire situation would be staged...","TWN":"完全中計了。原來整個情況都是你的安排……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"차라리 배우나 각본가가 되어보시는 건 어떨까요?","JPN":"どうですか？　俳優か脚本家になってみては。","ENG":"What do you think about becoming a scriptwriter or an actor?","TWN":"不如你試試來當演員或者編劇怎麼樣？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 과찬이로군.","JPN":"はは、それは嬉しい言葉だ。","ENG":"Haha, you flatter me.","TWN":"哈哈，你過獎了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"미안하지만, 내 업은 따로 있어서 말이야.","JPN":"ただ、残念ながら私には本業があるのでね。","ENG":"I'm sorry, but I already have a job.","TWN":"抱歉，我有自己的任務。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 이제 뭘 어쩌실 생각이죠?","JPN":"それで、今からどうするつもりですか？","ENG":"So, what are you going to do with it now?","TWN":"所以，現在你打算怎麼辦？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 그분의 사주를 받은 게 아니라 개인적인 목적으로 절 찾아왔다면…….","JPN":"あなたがあの方の使いではなく、個人的な目的があって私を訪ねたというのなら……","ENG":"If you came to see me for personal reasons and not the prince's...","TWN":"如果你不是受他指使，而是為了個人目的來找我的話……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아직 제게 협상의 여지가 남았다는 뜻으로 받아들이면 될까요?","JPN":"あなたとはまだ交渉の余地がある、と理解していいんでしょうか。","ENG":"does that mean that there is still room for me to negotiate?","TWN":"我可以理解為還有談判的餘地？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"역시 배우답게 눈치가 빠르군.","JPN":"さすがは役者だ。察しが早い。","ENG":"Just as I thought, you're a quick-witted actress.","TWN":"不愧是演員，觀察力很敏銳。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 전에 짚고 넘어가야 할 것이 있지 않나?","JPN":"しかしその前に一つ明確にしておくべきことがあるのではないか？","ENG":"But isn't there something we should go over first?","TWN":"但在那之前，我們是不是還有些事情沒有搞清楚？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 아직 말하지 않은 게 있을 텐데?","JPN":"君にはまだ、話していないことがあるはずだ。","ENG":"Don't you have something you want to say to me?","TWN":"你還有什麼沒說的嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……무슨 뜻이죠?","JPN":"……どういう意味ですか？","ENG":"...What do you mean?","TWN":"……你什麼意思？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 말씀드릴 수 있는 건 전부 말씀드렸습니다. 이제 와서 뭘 더 감추고 있다는 거죠?","JPN":"私は話せることはすべて話しました。それでもまだ何かを隠しているとおっしゃいたいんですか？","ENG":"I told you everything. Why do you think I'm still hiding something?","TWN":"我能告訴你的都已經說了。現在還要隱瞞什麼呢？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 감추고 있는 것…….","JPN":"君が隠していること……","ENG":"What you are hiding is...","TWN":"你想隱藏的東西……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 물론 왕세자께서 사진을 필사적으로 회수하려는 진짜 이유라네.","JPN":"それはもちろん、皇太子が写真を必死に回収しようとする本当の理由さ。","ENG":"the real reason the prince is trying so desperately to get that photo back.","TWN":"當然是王儲拼命想回收照片的真正原因啊。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"진짜 이유……? 무슨 헛소리를 하시는 거죠?","JPN":"本当の理由……？　何の話ですか？","ENG":"The real reason...? What kind of nonsense is that?","TWN":"真正的原因……？你在胡說什麼呢？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이미 말씀드렸을 텐데요? 그건 제 신분이 평민이라서……!","JPN":"先程説明したはずです。私が平民だから……！","ENG":"Didn't I already tell you? It’s because I'm a commoner–!","TWN":"我已經說過了吧？只不過因為我的身份是平民……！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그 이야기는 이미 들었어.","JPN":"いや、その話は聞いた。","ENG":"No, I heard that already.","TWN":"不，那件事我已經聽過了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 자네도 이미 짐작하고 있을 텐데?","JPN":"しかし君もすでに勘づいているはずだ。","ENG":"But you have an inkling of what I'm talking about, no?","TWN":"不過我想，你也應該隱約猜到了吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"단순히 평민이라는 것 때문에 목숨을 위협받고 있는 게 아니라는 것쯤은 말이야.","JPN":"単純に君の身分が平民だという理由で、命を脅かされている訳ではないということぐらい。","ENG":"I'm saying that the reason your life is at risk is not because you're just a commoner.","TWN":"你會受到生命威脅……並不是僅僅是平民的原因。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 나에 대해 잘 모르겠지만, 나는 자네에 대해 많은 걸 알고 있다네.","JPN":"君は私のことをよく知らないはずだが、私は君についてかなり多くのことを知っている。","ENG":"You may not know a lot about me, but I know a lot about you.","TWN":"你可能對我不太了解，但我對你可是所知甚多呢。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이를 테면, 자네가 이 나라 밖에서 온 이민자 출신이라는 것…….","JPN":"例えば、君が国外から来た移民ということや……","ENG":"For example, that you are an immigrant...","TWN":"比如說，你是來自這個國家之外的移民……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 <color=#ffd34c>이능력자</color>라는 사실을 숨기고 있다는 것도 말이지.","JPN":"君が<color=#ffd34c>異能力者</color>だという事実を隠していることなどだ。","ENG":"That you are hiding the fact that you are <color=#ffd34c>a Supernatural</color>.","TWN":"又比如說，你隱瞞了自己是<color=#ffd34c>超能力者</color>的事實。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 나라에 <color=#ffd34c>마석</color>이라는 에너지원이 발견된 것이 벌써 십 수년 전…….","JPN":"この国で<color=#ffd34c>魔石</color>というエネルギー源が見つかってから十数年が経つ……","ENG":"It's been decades since this country discovered <color=#ffd34c>Mana Stones</color>.","TWN":"這個國家發現名為<color=#ffd34c>魔石</color>的能源已有十多年之久……"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"덕분에 왕국은 혁신적인 기술의 발달로 단숨에 초강대국으로 성장하게 됐고.","JPN":"おかげで王国は革新的ともいえる技術の発達を遂げ、一気に強国として成長できた。","ENG":"Thanks to that, the kingdom was able to become a superpower through the development of innovative technology.","TWN":"多虧了它，王國憑藉革命性的技術發展，一躍成為超級大國。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"세계의 패권을 장악하여, 해가 지지 않는 나라가 될 수 있었어.","JPN":"世の覇権を掌握し、太陽の沈まない国になれた。","ENG":"Moreover, by becoming the world's hegemon, it was able to be the country where the sun never sets.","TWN":"掌握了世界的霸權，成為了一個日不落的國家。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 이면에는 여러 부작용이 있었지.","JPN":"しかしその裏では様々な副作用に悩まされている。","ENG":"However, that in itself is followed by several side effects.","TWN":"但背後也有許多副作用。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"마석 발견을 기점으로 정체불명의 마물과 수상한 능력을 가진 자들이 나타났거든.","JPN":"魔石の発見を境に、謎の魔物や怪しい能力を持つ者が現れたのさ。","ENG":"Since the discovery of Mana Stones, unidentified monsters and people with strange abilities have started to appear.","TWN":"自從發現魔石以來，也出現了不明身份的怪物和擁有可疑能力的人類。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"시간이 지나, 마석의 채굴량이 떨어지고 그 가격이 올라 빈부격차가 커지면서.","JPN":"時は流れ、魔石の採掘量減少によってその値段が大幅に上がり貧富の差は激しくなった。","ENG":"As time passed, the mining amount of Mana Stones decreased while its price soared, creating an even larger wealth gap.","TWN":"隨著時間的推移，魔石的開採量下降，價格上漲，貧富差距擴大。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"누구보다도 이능력자들이 경제적으로 큰 타격을 받았지.","JPN":"経済的にもっともダメージを受けたのは異能力者たちだったよ。","ENG":"It was the Supernaturals who were hurt most economically.","TWN":"超能力者受到了比任何人都更大的經濟打擊。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 그들은 살아가는 데 있어, 필수적으로 마석을 소모해야만 했으니까.","JPN":"なぜなら、彼らは生きるために魔石を消費し続けなければならなかったからね。","ENG":"Because in order for them to survive, they must consume Mana Stones.","TWN":"因為他們在生存過程中，必須消耗魔石。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지 않으면, 끔찍한 이형의 마물로 전락해 버리지.","JPN":"さもないと忌々しい異形の魔物に変わり果ててしまう。","ENG":"And if they didn't, they would turn into hideous monsters.","TWN":"否則，就會墮落成可怕的異形怪物。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"런던 그림자 사태…….","JPN":"ロンドンシャドウ事変……","ENG":"The London Shadow incident...","TWN":"倫敦暗影事件……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 자네도 잘 알고 있군.","JPN":"そうだ、君も知っているようだね。","ENG":"Yes, so you do know.","TWN":"沒錯，看來你也很了解啊。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 런던에서 마석을 구하지 못한 이능력자가 사람들 앞에서 마물로 변해버린 사건이지.","JPN":"数年前、魔石を手に入れることができなかったロンドンの異能力者が人前で魔物に豹変した事件だ。","ENG":"Years ago, there was an incident in London where a Supernatural who failed to acquire Mana Stones turned into a monster in front of the public.","TWN":"數年前，在倫敦，一名未能及時獲取魔石的超能力者在眾目睽睽之下變成了怪物。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 사건으로 이능력자는 런던 시민들에게 시한폭탄 같은 존재로 각인되어 버렸어.","JPN":"その事件で、ロンドンの市民たちに異能力者とは時限爆弾のような存在として記憶に刻み込まれてしまった。","ENG":"Through this, Supernaturals were branded as time bombs in the eyes of the London citizens.","TWN":"由於那次事件，超能力者在倫敦市民眼中成了定時炸彈般的存在。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실은 같은 사태를 방지한다는 명목으로 그들을 철저하게 통제하기 시작했지만.","JPN":"王室は同じ事態が再発しないよう、彼らを徹底的に統制しはじめたが……","ENG":"The royal family began to strictly control them in the name of preventing such a catastrophe from happening again, but...","TWN":"王室以防止類似事件為名，開始對他們實施徹底的控制。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럴 수록 이능력자들은 점점 더 그 정체를 숨기게 되었지.","JPN":"統制しようとすればするほど、異能力者たちは自分の正体を更に隠した。","ENG":"the more they suppressed, the more those Supernaturals started hiding who they were.","TWN":"因此，越來越多的超能力者開始隱瞞起自己的真實身份。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 바로 자네처럼 말이야.","JPN":"そう、君のようにね。","ENG":"Yes. Just like you.","TWN":"就和現在的你一樣。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"현재 여왕께서는 왕국 밖 마물과 전면전을 선포한 상태야.","JPN":"現在、女王は王国外の魔物と全面戦争をすると宣言している。","ENG":"Currently, the queen has declared an all-out war against the monsters outside the kingdom.","TWN":"目前女王已經對王國外的宣戰了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이런 상황에서 왕실은 불미스러운 스캔들을 절대 용납하지 않을 걸세.","JPN":"今のような状況で、王室は不祥事を決して許さないだろう。","ENG":"In their current state, the royal family will not tolerate such a scandal.","TWN":"在這種情況下，王室絕對不會容忍任何不光彩的醜聞。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실의 이미지와 전쟁의 명분을 위해서라도 필사적으로 부정하겠지.","JPN":"王室のイメージと戦争の口実を守るためにも、君のことは必死に否定するだろうさ。","ENG":"They will deny it completely for the sake of their reputation and reason for war.","TWN":"為了王室的形象和戰爭的名分，他們一定會對此否認。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 목숨을 위협받게 된 까닭은 그런 사정이 아니었을까?","JPN":"君が命を狙われているのは、そのせいじゃないかね？","ENG":"Is that not the reason why your life was threatened?","TWN":"你的生命會受到威脅，難道不就是因為這個原因嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……불쾌하네요.","JPN":"……不愉快ですね。","ENG":"...How dare you.","TWN":"……真煩。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 이능력자라는 건, 어디까지나 당신의 망상에 불과할 텐데요?","JPN":"私が異能力者だということは、あくまであなたの妄想話に過ぎません。","ENG":"Your claim that I'm a Supernatural is nothing more than your imagination.","TWN":"我是超能力者？那不過是你的妄想而已吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니면 당신의 주장을 뒷받침할 증거라도 있나요?","JPN":"その主張に根拠はあるのですか？","ENG":"Or do you have proof to support this ridiculous claim?","TWN":"那麼，有什麼證據能支持你的論斷呢？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 말하지 않았나?","JPN":"ふふ、だから先程言っただろう？","ENG":"Haha. Didn't I say?","TWN":"哈哈，我沒說過嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"나는 자네에 대해 많은 것을 알고 있다고.","JPN":"私は君について、多くのことを知っていると。","ENG":"I know a lot about you.","TWN":"關於你，我可是知道很多呢。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 자네는 이곳 런던에 오기 전에 다른 극장에 머물고 있었을 거야.","JPN":"数年前、君はこのロンドンに来る前に他の劇場に在籍していたはずだ。","ENG":"A few years ago, you were with another theater before coming to London.","TWN":"數年前，你在來到倫敦之前，應該還待在另一個劇院吧。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 왕세자와 사진을 찍었던 밀라노의 극장이지.","JPN":"そう、皇太子と写真を撮ったミラノの劇場にね。","ENG":"Yes, it was a theater in Milan when you took that photo with the prince.","TWN":"是的，這張照片也是當時你在米蘭的劇院和王儲拍的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……설마?","JPN":"……まさか？","ENG":"...Impossible...","TWN":"不對……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어떻게 거기까지? 그 시절의 흔적은 이미 다 지웠을 텐데……?","JPN":"いったいどうやってそこまで……？　あの頃の痕跡は全部消したはず……","ENG":"How do you know that? I thought I erased all traces of me from then...","TWN":"你到底是怎麼知道的？那時候的痕跡應該都已經抹去了……？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 과연 그럴까?","JPN":"ふふ、それはどうかね？","ENG":"Haha, is that so?","TWN":"呵呵，果真如此嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"한 번 이어진 인연의 끈은 그리 쉽게 끊어지지 않는다네.","JPN":"一度つながった因縁は、そう簡単には断ち切れないものさ。","ENG":"Once a bond is formed, it is not easily severed.","TWN":"結下的緣分之線，不會那麼輕易地斷開。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그때는 이능력자에 대한 인식이 지금처럼 나쁘진 않았던 시절이었어.","JPN":"あの頃は、異能力者に対する認識が今ほど悪化する前だった。","ENG":"Back then, the perception of Supernaturals was not as bad as it is now.","TWN":"那時候，人們對超能力者的看法還不像現在這麼糟糕。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"은퇴한 극장 관리인이 그 시절의 자네를 기억하더군.","JPN":"引退した劇場の支配人が君のことを覚えていたよ。","ENG":"The retired theater manager seemed to remember who you were.","TWN":"退休的劇院經紀人也還記得當年的你——"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 어리지만 유망한 배우라는 것. 완전 기억 능력을 가진 이능력자라는 것.","JPN":"君が幼くも有望な俳優で、完全記憶能力を持つ異能力者だということを。","ENG":"That you were a young and promising actress. And that you are a Supernatural with a perfect memory ability.","TWN":"那個雖然年輕，但卻大有前途的演員，也是個擁有完全記憶能力的超能力者。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 자네의 <color=#ffd34c>본명</color>까지도 말이야.","JPN":"そして君の<color=#ffd34c>本名</color>までもね。","ENG":"He even knew your <color=#ffd34c>real name</color>.","TWN":"以及，你的<color=#ffd34c>本名</color>……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 내 주장을 뒷받침할 증거를 요구했지?","JPN":"君は、私の主張に根拠があるのかと聞いただろう？","ENG":"You asked for proof to support my claim, right?","TWN":"你剛才要求我提供證據來支援我的推論吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 팬레터 속에 든 사진이 그 증거라네.","JPN":"このファンレターの中身がその証拠さ。","ENG":"The photo within this fan letter is my proof.","TWN":"這封粉絲信裡的照片就是證據。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 이 캐비닛 카드 사진에는 두 사람의 이름이 서명되어 있거든.","JPN":"このキャビネットカードの写真には、二人の署名が入っているからね。","ENG":"Because this cabinet card is signed by two people.","TWN":"因為那上面簽有兩個人的名字。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳嗯！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하나는 당연히 남성의 이름. 왕세자의 성함이지. 또다른 하나는…….","JPN":"一つは男性の名前。もちろん、皇太子のお名前だ。そしてもう一つは……","ENG":"One is a man's name, the crown prince. And...","TWN":"其中一個當然是男性的名字，也就是我們的王儲。另一個……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"밀라노 극장에서 쓰던 자네의 본명이지.","JPN":"ミラノの劇場で君が名乗っていた……君の本名だ。","ENG":"The other is your real name used in Milan.","TWN":"則是你在米蘭劇院使用的真名。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 이름은…….","JPN":"その名前は……","ENG":"That name is–","TWN":"而那個名字是……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그만. 이제 됐어요.","JPN":"もう結構です。わかりましたから。","ENG":"Stop. Enough.","TWN":"好了，已經夠了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사진을 빼앗긴 시점에서 이미 제 패배였네요.","JPN":"写真を奪われた時点で、私の負けでしたね。","ENG":"It was my defeat from the second that photo was out of my possession.","TWN":"從照片被搶走的那一刻起，我就已經輸了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"누구나 무대 위에 서려면, 그에 걸맞은 이름이 필요한 법이랍니다.","JPN":"舞台に立つ者なら、それに見合った名前が必要になります。","ENG":"To stand on stage, one must have a suitable name.","TWN":"任何人想要站上舞台，都需要一個與之相稱的名字。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 그 이름으로 부르지 마세요. 그 이름으로 불렸던 무명 시절은 막을 내렸으니까.","JPN":"ですがその名前で呼ばれていた無名時代は、もう幕を下ろしました。だからもうその名前では呼ばないでください。","ENG":"So please do not call me by that name. My days as an unknown actress with that name have already come to an end.","TWN":"所以不要再用那個名字叫我了。那個作為默默無名女演員的時期已經結束了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"지금의 저는 <color=#ffd34c>스완</color>. 스완 클레어라고 불러주세요.","JPN":"今の私は<color=#ffd34c>スワン</color>。スワン・クレアと呼んでください。","ENG":"Now, I am <color=#ffd34c>Swan</color>. Please refer to me as Swan Claire.","TWN":"現在的我是<color=#ffd34c>史旺</color>。請叫我史旺·克萊爾。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 이름이. 런던이라는 무대에 서면서 스스로 정한 배역의 이름이니까요.","JPN":"その名こそ、ロンドンという舞台に立った時自分で決めた役の名前なのです。","ENG":"This name is the name of the role I chose for myself while I stood on stage in London.","TWN":"這個名字，是我為了站在倫敦這個舞台上，為自己所選擇的角色名。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"스완. 스완이라…….","JPN":"スワン。スワンか……","ENG":"Swan. Swan...","TWN":"史旺，史旺……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"어감이 마음에 드는군. 근사한 이름이야. 자네가 원한다면 그렇게 부르지.","JPN":"いい響きだ。素敵な名前だよ。君が望むなら、そう呼ばせてもらおう。","ENG":"I like how it sounds. It's a wonderful name. I will call you by that as you wish.","TWN":"這個名字聽起來……很棒。如果你願意的話，我就這麼叫你。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 당신은요?","JPN":"それで、あなたは？","ENG":"And who are you?","TWN":"那麼你呢？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"레이디의 비밀을 함부로 파헤친 주제에, 당신은 지금껏 이름도 밝히지 않으셨잖아요?","JPN":"レディーの秘密を暴いておいて、あなたは今まで自分の名を名乗っていない。","ENG":"You are rude to pry into a lady's secrets, but you have never revealed your name to me.","TWN":"無禮地揭開女士的秘密，卻連自己的名字都不肯透露嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"재미있군.","JPN":"面白い。","ENG":"Interesting.","TWN":"有趣。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 누구나 무대에 서려면, 걸맞은 이름이 필요하다고 했지?","JPN":"そうか、舞台に立つ者なら、見合った名前が必要だと言ったな。","ENG":"Very well. You said that one must have a suitable name to stand on stage.","TWN":"是啊，任何人想要登上舞台，都需要一個合適的名字。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"프레드릭 애버라인.","JPN":"フレデリック・アバーライン。","ENG":"I am Fredrick Abberline.","TWN":"弗雷德里克·艾伯林。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인이라고 불러주게.","JPN":"アバーラインと呼びたまえ。","ENG":"But you can call me Abberline.","TWN":"叫我艾伯林吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 고약한 취미를 가지신 분이로군요. 당신은.","JPN":"あなたは本当にひどい趣味の持ち主ですね。","ENG":"You have a nasty hobby, Abberline.","TWN":"你真是個奇怪的人，艾伯林。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"남의 비밀을 헤집어 놓을 만큼 헤집어 놓았다면, 슬슬 대답해 주실 때가 되지 않았나요?","JPN":"人の秘密を勝手に暴いたのなら、そろそろ教えてくれてもいいんじゃないですか？","ENG":"Don't you think it's time you answered after digging around another's secrets?","TWN":"既然已經把別人的秘密公開了，是不是該給個答覆了呢？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 사진은 어떻게 할 생각이죠?","JPN":"あの写真は、どうするつもりですか？","ENG":"What are you going to do with the photo?","TWN":"那張照片你打算怎麼處理？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 어떤 목적으로 저에게 접근한 건가요?","JPN":"そもそも何を目的に私に近づいたんですか？","ENG":"What was your purpose of approaching me in the first place?","TWN":"一開始你是抱著什麼目的接近我的？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후. 걱정하지 말게. 이 사진이 왕세자께 들어갈 일은 없을 테니까.","JPN":"ふふ、心配しなくてもいい。この写真が皇太子の手に入ることはない。","ENG":"Haha. Don't worry. The prince will never get his hands on this photo.","TWN":"呵呵。別擔心，這張照片絕不會傳到王儲手中的。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 말은……?","JPN":"ということは……？","ENG":"That means...","TWN":"你的意思是……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대신, 사진을 돌려받고 싶다면 조건이 있네.","JPN":"ただ、写真を取り戻したいのなら一つ条件がある。","ENG":"There is a condition if you wish to have the photo back.","TWN":"不過，如果你拿回它的話，有個條件。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아주 간단한 조건이지.","JPN":"とてもシンプルな条件さ。","ENG":"It's a rather simple request, actually.","TWN":"非常簡單的條件。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……조건?","JPN":"……条件？","ENG":"...Condition?","TWN":"……條件？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 내 파트너가 되어주었으면 해.","JPN":"君に、私のパートナーになってほしい。","ENG":"I want you to be my partner.","TWN":"希望你能成為我的搭檔。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 뭐라고요!?","JPN":"な、なんですって！？","ENG":"W-what?!","TWN":"什，什麼？!"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 오랜 벗이 그만 결혼을 해버렸거든. 그래서 마침 새로운 파트너가 필요한 참이었네.","JPN":"私の旧友が結婚をしてしまってね。ちょうど今、新しいパートナーが必要なのさ。","ENG":"An old friend got married, so I have been searching for a new partner.","TWN":"我的老朋友結婚了。所以正好需要一個新的搭檔。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 자네라면……. 내 파트너로서 손색이 없을 것 같군.","JPN":"そう、君なら……私のパートナーとして遜色ないだろう。","ENG":"And I think... that you would make a great partner.","TWN":"是的，如果是你的話……作為我的搭檔應該很合適。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이, 이이! 저질이……!!","JPN":"な、なんて……低俗なことを……！！","ENG":"Y-you! Disdainful...!!","TWN":"哼，哼！卑鄙的傢伙……！！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"듣자 듣자 하니 이젠 정말 못 들어주겠군요!","JPN":"何を言い出すのかと思ったら……聞いていられないですね！","ENG":"I've had enough of you!","TWN":"耐著性子聽了這麼多，我實在是受夠了！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그깟 스캔들 때문에 절 가벼운 여자 취급하는 모양인데, 완전히 헛다리 짚으신 거예요!","JPN":"スキャンダルのせいで、私を軽い女として見ているようですが、とんだ勘違いです！","ENG":"I believe you're treating me like some shallow woman because of that photo, but you are completely mistaken!","TWN":"你要是因為那個醜聞就把我當成輕浮的女人，那就真是大錯特錯了！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저에게도 배우로서의 프라이드가 있으니까요……!","JPN":"私にも役者としてのプライドが……！","ENG":"I also have pride as an actress...!","TWN":"我也有作為演員的自尊心……！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네, 지금 무슨 말을 하는 거지?","JPN":"君、何を言っているんだ？","ENG":"What are you talking about?","TWN":"呃……你現在在說什麼？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 말은……. 함께 수수께끼를 풀 수사 파트너가 필요하다는 말이었네.","JPN":"私は……一緒に謎を解いてくれる捜査のパートナーになって欲しいと言っている。","ENG":"I was saying... that I needed a partner to solve a mystery with me.","TWN":"我的意思是……需要一個能一起解開謎題的調查夥伴。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……수, 수수께끼?","JPN":"……な、謎？","ENG":"...M-mystery?","TWN":"……謎，謎題？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 이미 알고 있지 않나.","JPN":"君も知っているだろう。","ENG":"You know of it.","TWN":"你難道不清楚嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현재 런던에서 일어나고 있는 연쇄 살인, <color=#ffd34c>심야의 살인마</color> 사건에 대해서 말이야.","JPN":"今ロンドンで起きている連続殺人、<color=#ffd34c>深夜の殺人鬼</color>事件について。","ENG":"The serial killings that have been going on in London. The <color=#ffd34c>Midnight Killer</color> case.","TWN":"關於目前在倫敦發生的連環殺人案，<color=#ffd34c>午夜殺人魔</color>事件。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마 사건이라면…….","JPN":"深夜の殺人鬼事件って……","ENG":"The Midnight Killer case...?","TWN":"午夜殺人魔事件……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"런던의 밤을 배회하며 여자들을 노린다는 그 사건 말인가요?","JPN":"夜のロンドンを徘徊し、女性だけ狙うというあの殺人鬼ですか？","ENG":"Do you mean the one that roams the night streets of London preying on women?","TWN":"是指在倫敦的夜晚徘徊，專門針對女性下手的那一系列兇殺案嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 그 심야의 살인마를 제때 막아내지 못한다면 런던, 아니…….","JPN":"ああ、深夜の殺人鬼を早く捕まえないとロンドンが……いや……","ENG":"Yes. If he isn't stopped, the London– no...","TWN":"對。如果不能及時阻止那個午夜殺人魔，倫敦，不……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리 세계 전체가 멸망할지도 모르니까.","JPN":"この世界が滅びるかもしれない。","ENG":"our entire world might perish.","TWN":"我們的世界可能會徹底毀滅。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"네에……?","JPN":"はあ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};